Definition ispreidem_homotopic {X : Type}
           (f : X -> X) `{IsPreIdempotent _ f} {g : X -> X} (p : f == g)
: IsPreIdempotent g.

goals.conclusion:
(fun R : RetractOf X => retract_idem R == f)
  {|
    retract_type := {x : X & f x = x};
    retract_retr := fun x : X => (f x; isidem f x);
    retract_sect := pr1;
    retract_issect := ?retract_issect
  |}

